// Procesar CPI USA (Consumer Price Index) de EconDB
// Usado por MSK Energy para contexto macro de costos de combustibles
const raw = items[0].json;

// EconDB puede devolver resultados en formato array o con key 'results'
const series = raw?.results || raw?.data || (Array.isArray(raw) ? raw : [raw]);

if (!series || series.length === 0) {
  return [{ json: { error: 'Sin datos CPI', raw: raw, timestamp: new Date().toISOString() } }];
}

const entry = series[0];
const dates = entry?.dates || [];
const values = entry?.values || [];

// Tomar los últimos 3 puntos de datos
const recientes = dates.slice(-3).map((d, i) => ({
  fecha: d,
  cpi: values[dates.length - 3 + i]
}));

const ultimo = recientes[recientes.length - 1];
const anterior = recientes[recientes.length - 2];

const cambio_mensual = ultimo && anterior && anterior.cpi
  ? (((ultimo.cpi - anterior.cpi) / anterior.cpi) * 100).toFixed(3)
  : null;

const resultado = {
  agente: 'MSK BROKER',
  fuente: 'EconDB — CPIUS',
  indicador: 'CPI USA (Inflación al consumidor)',
  ultima_fecha: ultimo?.fecha,
  cpi_actual: ultimo?.cpi,
  cambio_mensual_pct: cambio_mensual,
  tendencia: cambio_mensual > 0 ? '⬆️ Inflación subiendo' : '⬇️ Inflación bajando',
  impacto_combustible: cambio_mensual > 0.5 ? '⚠️ Presión al alza en costos MSK' : 'Estable',
  historico_3m: recientes,
  timestamp: new Date().toISOString()
};

console.log('[MSK]', JSON.stringify(resultado, null, 2));
return [{ json: resultado }];
